    <div
      data-testid="view-cube"
      role="group"
      aria-label="ViewCube"
      onKeyDown={handleKey}
      className={['group flex flex-col items-center gap-1.5', className ?? ''].join(' ')}
    >
      {/* Stage: drag here to orbit; click a face/corner to snap. */}
      <div
        data-testid="view-cube-stage"
        style={{ ...stageStyle, filter: 'drop-shadow(0 2px 8px rgba(0,0,0,0.22))' }}
        onPointerDown={handlePointerDown}
        onClickCapture={handleClickCapture}
      >
        <div style={cubeStyle} data-cube-stage="true">
          {FACES.map((face) => (
            <CubeFace
              key={face.id}
              face={face}
              onClick={() => emit({ kind: 'face', face: face.id })}
            />
          ))}
        </div>

        {/* Corner snap targets: invisible by default, appear on cube hover. */}
        {TOP_CORNERS.map((c) => (
          <button
            key={c.id}
            type="button"
            onClick={() => emit({ kind: 'corner', corner: c.id })}
            aria-label={`Align camera to ${c.id}`}
            data-corner={c.id}
            style={{
              position: 'absolute',
              left: c.left,
              top: c.top,
              transform: 'translate(-50%, -50%)',
              width: 10,
              height: 10,
              borderRadius: 5,
              border: '1px solid var(--color-border)',
              background: 'var(--color-surface)',
              cursor: 'pointer',
              padding: 0,
              transition: 'opacity 150ms',
            }}
            className="opacity-0 group-hover:opacity-60 hover:!opacity-100"
          />
        ))}
      </div>

    </div>
  );
}

function CubeFace({ face, onClick }: { face: FaceDef; onClick: () => void }): JSX.Element {
  const bgColor =
    face.shade === 0
      ? 'var(--color-surface)'
      : `color-mix(in srgb, var(--color-surface) ${Math.round((1 - face.shade) * 100)}%, var(--color-foreground) ${Math.round(face.shade * 100)}%)`;

  const style: CSSProperties = {
    position: 'absolute',
    inset: 0,
    transform: face.transform,
    background: bgColor,
