    fontWeight: 600,
    letterSpacing: '0.1em',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    cursor: 'grab',
    backfaceVisibility: 'hidden',
    boxShadow: 'inset 0 0 0 1px color-mix(in srgb, var(--color-border) 40%, transparent)',
    userSelect: 'none',
    opacity: 0.9,
