20	 * ViewCube widget — spec §15.4.
21	 *
22	 * 96 × 96 px CSS-3D cube sitting top-right of the 3D canvas. Faces +
23	 * top corners are clickable (snap camera to that alignment). The cube
24	 * also supports drag-to-orbit: dragging anywhere on the stage orbits
25	 * the main camera live via the `onDrag` callback.
26	 *
27	 * The cube tracks the camera's full pose (azimuth + elevation) rather
28	 * than only azimuth, so it mirrors the scene orientation exactly.
29	 */
30	
31	export interface ViewCubeProps {
32	  currentAzimuth: number;
33	  /** Camera elevation in radians (0 = horizontal, π/2 = straight down). */
34	  currentElevation: number;
35	  onPick: (pick: ViewCubePick, alignment: ViewCubeAlignment) => void;
36	  /** Raw pixel deltas during a drag. Viewport calls rig.orbit(dx, dy). */
37	  onDrag?: (dxPx: number, dyPx: number) => void;
38	  onHome?: () => void;
39	  /** Optional className for positioning. */
40	  className?: string;
41	}
42	
43	const CUBE_SIZE_PX = 68;
44	const HALF = CUBE_SIZE_PX / 2;
45	const DRAG_THRESHOLD_PX = 4;
46	
47	const TOP_CORNERS: { id: ViewCubeCorner; left: string; top: string }[] = [
48	  { id: 'TOP-NW', left: '6%', top: '6%' },
49	  { id: 'TOP-NE', left: '94%', top: '6%' },
50	  { id: 'TOP-SW', left: '6%', top: '94%' },
51	  { id: 'TOP-SE', left: '94%', top: '94%' },
52	];
53	
54	interface FaceDef {
55	  id: ViewCubeFace;
56	  label: string;
57	  transform: string;
58	  /** Fraction of --color-foreground mixed into --color-surface (0–1). */
59	  shade: number;
60	}
61	
62	const FACES: FaceDef[] = [
63	  { id: 'FRONT', label: 'FRONT', transform: `rotateY(0deg) translateZ(${HALF}px)`, shade: 0.04 },
64	  { id: 'BACK', label: 'BACK', transform: `rotateY(180deg) translateZ(${HALF}px)`, shade: 0.12 },
65	  { id: 'RIGHT', label: 'RIGHT', transform: `rotateY(90deg) translateZ(${HALF}px)`, shade: 0.08 },
66	  { id: 'LEFT', label: 'LEFT', transform: `rotateY(-90deg) translateZ(${HALF}px)`, shade: 0.08 },
67	  { id: 'TOP', label: 'TOP', transform: `rotateX(90deg) translateZ(${HALF}px)`, shade: 0.0 },
68	  {
69	    id: 'BOTTOM',
70	    label: 'BTM',
71	    transform: `rotateX(-90deg) translateZ(${HALF}px)`,
72	    shade: 0.22,
73	  },
74	];
