76	export function ViewCube({
77	  currentAzimuth,
78	  currentElevation,
79	  onPick,
80	  onDrag,
81	  onHome,
82	  className,
83	}: ViewCubeProps): JSX.Element {
84	  const dragRef = useRef({ dragging: false, totalMoved: 0 });
85	  const suppressNextClickRef = useRef(false);
86	  const [isDragging, setIsDragging] = useState(false);
87	
88	  function emit(pick: ViewCubePick): void {
89	    onPick(pick, alignmentForPick(pick));
90	  }
91	
92	  function handleKey(event: KeyboardEvent<HTMLDivElement>): void {
93	    if (event.key === 'Enter' || event.key === ' ') {
94	      event.preventDefault();
95	      emit({ kind: 'home' });
96	      onHome?.();
97	    }
98	  }
99	
100	  const handlePointerDown = useCallback(
101	    (e: React.PointerEvent<HTMLDivElement>) => {
102	      if (e.button !== 0) return;
103	      dragRef.current = { dragging: true, totalMoved: 0 };
104	      setIsDragging(true);
105	      document.body.style.cursor = 'grabbing';
106	
107	      const onMove = (ev: PointerEvent) => {
108	        const dx = ev.movementX;
109	        const dy = ev.movementY;
110	        dragRef.current.totalMoved += Math.abs(dx) + Math.abs(dy);
111	        onDrag?.(dx, dy);
112	      };
113	
114	      const onUp = () => {
115	        if (dragRef.current.totalMoved > DRAG_THRESHOLD_PX) {
116	          suppressNextClickRef.current = true;
117	        }
118	        dragRef.current.dragging = false;
119	        setIsDragging(false);
120	        document.body.style.cursor = '';
121	        window.removeEventListener('pointermove', onMove);
122	        window.removeEventListener('pointerup', onUp);
123	      };
124	
125	      window.addEventListener('pointermove', onMove);
126	      window.addEventListener('pointerup', onUp);
127	    },
128	    [onDrag],
129	  );
130	
131	  const handleClickCapture = useCallback((e: React.MouseEvent) => {
132	    if (suppressNextClickRef.current) {
133	      e.stopPropagation();
134	      suppressNextClickRef.current = false;
135	    }
136	  }, []);
137	
138	  // Cube orientation mirrors camera exactly: azimuth = horizontal rotation,
139	  // elevation = vertical tilt. The -elevation maps camera look-direction to
140	  // cube top-down rotation (elevation=0 → see front face, elevation=π/2 → see top face).
141	  const azimuthDeg = (-currentAzimuth * 180) / Math.PI;
142	  const elevationDeg = (currentElevation * 180) / Math.PI;
143	
144	  const stageStyle: CSSProperties = {
145	    perspective: '320px',
146	    width: CUBE_SIZE_PX,
147	    height: CUBE_SIZE_PX,
148	    position: 'relative',
149	    cursor: isDragging ? 'grabbing' : 'grab',
150	  };
151	
